```cpp
#include <iostream>
#include <vector>
using namespace std;

int main() {
    int n;
    cin >> n;

    vector<int> parent(n);
    for(int i = 0; i < n; ++i) {
        cin >> parent[i];
        --parent[i]; // Convertem indexuri la 0-based
    }

    bool hasEvenDegree = false;
    vector<bool> visited(n, false);
    queue<int> q;

    for(int i = 0; i < n; ++i) {
        if(parent[i] == -1) {
            q.push(i);
            visited[i] = true;
        } else {
            if(!visited[parent[i]]) {
                visited[parent[i]] = true;
                q.push(parent[i]);
            }
        }

        while(!q.empty()) {
            int u = q.front();
            q.pop();

            if(parent[u] != -1 && !visited[parent[u]]) {
                visited[parent[u]] = true;
                q.push(parent[u]);
            }

            if(parent[u] == -1 || visited[parent[u]]) continue;

            if(parent[u] % 2 == 0) {
                hasEvenDegree = true;
                break;
            }
        }

        if(hasEvenDegree) break;
    }

    if(hasEvenDegree) cout << "NO\n";
    else {
        cout << "YES\n";
        for(int i = 0; i < n; ++i) {
            if(!visited[i]) {
                cout << i + 1 << "\n";
            }
        }
    }

    return 0;
}
```

