[Enunț] The rebels need to determine which sets of spaceships should be operated to maximize the total profit while considering dependencies among the pilots.
[Abordare] To solve this problem, we can use dynamic programming combined with a priority queue to efficiently manage the operations of the spaceships based on their profits and dependencies.
[Complexitate] O(n + m log n) timp, O(n + m) spațiu
[Cod]
```cpp
#include <iostream>
#include <vector>
#include <queue>
using namespace std;

const int MAXN = 100;
const int INF = 1e9;

int n, m;
vector<vector<int>> adj(MAXN);
priority_queue<pair<long long, pair<int, int>>> pq;
bool visited[MAXN];

void dijkstra(int src) {
    fill(visited, visited + n, false);
    vector<long long> dist(n, INF);
    dist[src] = 0;
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> q;
    q.push({0, src});

    while (!q.empty()) {
        auto [d, u] = q.top();
        q.pop();

        if (visited[u]) continue;
        visited[u] = true;

        for (auto &v : adj[u]) {
            if (dist[v] > d + 1) {
                dist[v] = d + 1;
                q.push({dist[v], v});
            }
        }
    }
}

long long dp[1 << 10][MAXN];
int main() {
    cin >> n >> m;
    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        --u, --v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    int s, b, k;
    cin >> s >> b >> k;
    for (int i = 0; i < s; ++i) {
        int x, a, f, p;
        cin >> x >> a >> f >> p;
        --x;
        pq.push({-a - f + p, {x, 0}});
    }
    for (int i = 0; i < b; ++i) {
        int x, d, g;
        cin >> x >> d >> g;
        --x;
        pq.push({g, {x, d}});
    }

    for (int mask = 0; mask < (1 << s); ++mask) {
        for (int i = 0; i < n; ++i) {
            dp[mask][i] = -INF;
        }
    }

    while (!pq.empty()) {
        auto [cost, {x, y}] = pq.top();
        pq.pop();

        if (y == 0 && !visited[x]) {
            visited[x] = true;

            for (int i = 0; i < n; ++i) {
                if (dp[mask][i] < cost + y) {
                    dp[mask][i] = cost + y;
                    pq.push({-dp[mask][i], {i, 0}});
                }
            }
        } else if (y != 0 && dp[mask][x] < cost + y) {
            dp[mask][x] = cost + y;
            pq.push({-dp[mask][x], {x, y}});
        }
    }

    long long ans = 0;
    for (int i = 0; i < n; ++i) {
        if (dp[(1 << s) - 1][i] >= 0) {
            ans += pq.top().first;
            pq.pop();
        }
    }

    cout << ans << endl;
}
```

[Enunț] 
Un hotel de smii este construit pentru a eleva emoțiile. Este compus din n chatele. Unele dintre chatele sunt conectate prin portiere. Pentru fiecare doi chatele (numărul i și j), care sunt conectate prin o portieră, Petya știe valoarea cij - valoarea care este adaugată la emoțiile sale atunci când se move din chatele i în chatele j.

Petya își simt că poate eleva emoțiile infinit, fiindcă, sălătoriul cu emoțiile poate fi parcurs prin o ciclu? Dacă el poate, atunci ce minim număr de chatele trebuie să-l viziteze într-o perioadă a ciclului?

Input

Primul linie conține două numere pozitive întregi n și m (<image>, unde n este numărul de chatele și m este numărul de portiere din hotelul de smii). În urma descrierii portierei: m linii, fiecare conținând patru numere intregi i, j, cij și cji (1 ≤ i, j ≤ n, i ≠ j, - 10^4 ≤ cij, cji ≤ 10^4). Se garantează că nu există mai multă uneori un portier care connecte doar două chatele. Niciun portier nu se conectează cu chatele sa însuși.

Output

Imparte numărul minim de chatele care trebuie vizitat într-o traversare a ciclului. Dacă astfel de ciclul nu există, imparte numărul 0.

Exemple

Input

4 4
1 2 -10 3
1 3 1 -10
2 4 -10 -1
3 4 0 -3

Output

4

Notație:

Ciclu este cumva secvența de chatele a1, a2, ..., ak, către a1. Chatelele din secvența pot fi echivalente, astfel încât ciclul nu ar trebui să fie simplu. Numărul de chatele din ciclul este considerat ca k, iar lungimea secvenței. Notă că cel mai mic posibil număr de chatele este de dimensiunea 2.

Ideea de rezolvare:
În primul rând, am analizat structura dată și am observat că există câteva condiții necesare pentru ca un ciclu să existe. De exemplu, dacă un chatele este conexat cu un alt chatele, atunci este nevoie de un alt chatele pentru a putea face un ciclu. Acest lucru implică că ambele chatele trebuie să fie partene ale unui singur subgrup al chatelelor.

Dacă această conditie este respectată, avem nevoie de calcularea minimală a numărului de chatele care trebuie vizitat într-un ciclu. Aceasta poate fi realizată folosind algoritmul de minimim Spanning Tree (MST) sau algoritmul de Prim pentru a găsi un MST al grafului. Algoritmul MST va ajuta să identificăm cele mai puțini chatele care trebuie vizitat pentru a forma un ciclu valid.

Cod:
```cpp
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<vector<int>> graph(n + 1);
    for(int i = 0; i < m; ++i) {
        int u, v, w, x;
        cin >> u >> v >> w >> x;

        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    vector<bool> visited(n + 1, false);
    vector<int> parent(n + 1, -1);
    vector<long long> distance(n + 1, INT_MAX);

    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    pq.push({0, 1});

    while(!pq.empty()) {
        auto [dist, node] = pq.top();
        pq.pop();

        if(visited[node]) continue;

        visited[node] = true;
        distance[node] = dist;

        for(auto neighbor : graph[node]) {
            if(distance[neighbor] > dist + w) {
                distance[neighbor] = dist + w;
                parent[neighbor] = node;

                pq.push({distance[neighbor], neighbor});
            }
        }
    }

    int minRooms = 0;
    for(int i = 1; i <= n; ++i) {
        if(parent[i] != -1 && parent[parent[i]] == i) {
            minRooms++;
        }
    }

    cout << minRooms << endl;

    return 0;
}
```

Explicație:
- Am initializat o matrice de adiacență pentru graful.
- Am implementat algoritmul Prim pentru a găsi MST al grafului.
- Am utilizat o piață prioritara pentru a ordona nodurile după distanța de la origine.
- După ce am gasit MST, am verificat dacă orice chatele este partene al unui singur subgrup al chatelelor. Dacă acest lucru este sigur, atunci am determinat numărul minim de chatele care trebuie vizitat într-un ciclu.
- Final, am afisat numărul minim de chatele care trebuie vizitat într-o traversare a ciclului.

[Enunț] 
Unui duminică Polycarpus a primit o zi cu vârsta de săptămâna. A fost nevoie pentru a se întoarce la casa sa, dar în viața sale de la supermarina a avut o ofertă specială pentru piași. Ofertele sunt ca următoarea: dacă uneleul cumpărătoriul echipajul contine cel puțin un piaș, el va avea un reducere de 50% la prețul cea mai bogat produs din echipajul ei (acestea devin două ori mai bogate). Dacă există mai multe produse cu prețuri egale, reducerea aplicată este doar pentru unul dintre ele!

Polycarpus are k echipajuri, iar el vorbește cu adevărat că îl vorbesc cu toți piașurile și penilele din supermarina. Ajuta-l să distribuie piașurile și penilele între echipajurile, astfel încât suma preturilor totelor produselor (înclusiv reducării) ar fi cel mai mic posibil.

Polycarpus trebuie să folosească toate k echipajuri pentru a obține produsele, nu poate avea un echipajul sau penilă vazut. Când-e posibil, fiecare echipaj poate conține orice număr de piașuri și/ sau penile. 

Întrebarea:

Numărul de produse din supermarina și numărul de echipajuri disponibile.
Câte produse sunt piașuri și câte sunt penile?

Rezolvare:
Acest lucru este foarte simplu! Poți să ai o abordare bazată pe metoda minimului maxim. Într-adevăr, pentru a face o reducere de 50%, trebuie să ai cel puțin un piaș în echipajul dumneavoastră. Deci, pentru a ajuta Polycarpus să ia cel mai mic preț total, trebuie să te concentrezi pe piașurile. Piașurile pot fi distribuite între echipajurile în mod egal, dar penilele pot fi distribuate în mod diferit. 

Complexitate:
O(n) timp, O(1) spațiu

Cod:
```cpp
#include <iostream>
#include <vector>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;

    vector<pair<int, int>> items(n);
    for(int i = 0; i < n; ++i){
        string s;
        cin >> items[i].first >> items[i].second;
    }

    sort(items.begin(), items.end());

    double minTotalPrice = numeric_limits<double>::max();
    vector<vector<int>> bestDistribution(k);

    for(int i = 0; i < n; ++i){
        int currentCartPrice = 0;

        for(int j = 0; j < k; ++j){
            if(bestDistribution[j].size() == 0 || bestDistribution[j].back() != items[i].second){
                bestDistribution[j].push_back(items[i].second);
                currentCartPrice += items[i].first * 0.5;
            } else {
                currentCartPrice += items[i].first;
            }

            if(currentCartPrice <= minTotalPrice){
                minTotalPrice = currentCartPrice;
                break;
            }
        }
    }

    cout << fixed << setprecision(1) << minTotalPrice << endl;

    for(auto &cart : bestDistribution){
        cout << cart.size() << ' ';
        for(int item : cart)
            cout << item << ' ';
        cout << endl;
    }

    return 0;
}
