int main() {
    int a, b;
    cin >> a >> b;

    // Verificăm dacă cele două părți sunt egale
    if (a == b) {
        cout << 0 << endl;
        return 0;
    }

    // Verificăm dacă există o masă divizibilă cu 2
    if (a % 2 == 0) {
        a /= 2;
    } else {
        a++;
    }

    // Verificăm dacă există o masă divizibilă cu 3
    if (b % 3 == 0) {
        b /= 3;
    } else {
        b += 2;
    }

    // Verificăm dacă există o masă divizibilă cu 5
    if (b % 5 == 0) {
        b /= 5;
    } else {
        b += 4;
    }

    // Verificăm dacă cele două părți sunt egale
    if (a == b) {
        cout << 0 << endl;
        return 0;
    }

    // Calculăm câte operări trebuie făcute pentru a face ca cele două părți să fie egale
    int count = 0;
    while (a != b) {
        if (a > b) {
            a -= 2;
        } else {
            b -= 3;
        }
        count++;
    }

    cout << count << endl;
    return 0;
}
