#include<iostream>
using namespace std;

long long phi(long long n){
    long long result = n;
    for(long long i=2; i*i<=n; ++i){
        if(n % i == 0){
            while(n % i == 0)
                n /= i;
            result -= result / i;
        }
    }
    if(n > 1)
