#include<iostream>
using namespace std;

int fibonacci(int n){
    int f[n+1];
    f[0]=f[1]=1;
    for(int i=2; i<=n; i++){
        f[i]=f[i-1]+f[i-2];
    }
    return f[n];
}

void solve(){
    int t;
    cin>>t;
    while(t--){
        int n;
        cin>>n;
        cout<<fibonacci(n)<<endl;
    }
}

