```cpp
#include<iostream>
#include<vector>
using namespace std;

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> arr(n);
        for(int i = 0; i < n; i++) {
            cin >> arr[i];
        }

        // Formulăm noua lista
        vector<int> newArr(n * n);
        for(int i = 0; i < n; i++) {
            for(int j = 0; j < n; j++) {
                newArr[i * n + j] = arr[j];
            }
        }

        // Calculăm lungimile celor mai lungi secvente crescute
        int maxLIS = 1;
        for(int i = 0; i < n * n; i++) {
            int currentLength = 1;
            for(int j = i - 1; j >= 0 && arr[j] < arr[i]; j--) {
                currentLength++;
            }
            maxLIS = max(maxLIS, currentLength);
        }

        cout << maxLIS << endl;
    }

    return 0;
}
